/**
 * NetworkedStorage Strategy - WebSocket backend communication
 * Implements IStorageStrategy for networked mode operation
 *
 * @module core/storage/NetworkedStorage
 */

import { IStorageStrategy } from './IStorageStrategy.js';
import { calculateTokenValue } from '../scoring.js';
import { buildGameActivity } from '../gameActivityBuilder.js';

export class NetworkedStorage extends IStorageStrategy {
  /**
   * Create NetworkedStorage instance
   * @param {Object} options - Dependencies
   * @param {Object} options.socket - Socket.io client
   * @param {Object} options.tokenManager - TokenManager instance
   * @param {Object} [options.debug] - Debug instance
   */
  constructor({ socket, tokenManager, debug } = {}) {
    super();

    this.socket = socket;
    this.tokenManager = tokenManager;
    this.debug = debug;

    // Local cache (synced from backend)
    this.transactions = [];
    this.backendScores = new Map();
    this.scannedTokens = new Set();
    this.playerScans = [];
    this.currentSessionId = null;
  }

  /**
   * Check if storage is ready/connected
   * @returns {boolean}
   */
  isReady() {
    return this.socket?.connected === true;
  }

  /**
   * Send a gm:command via WebSocket with AsyncAPI envelope
   * @param {string} action - Command action (e.g., 'session:create')
   * @param {Object} payload - Command payload data
   * @private
   */
  _emitCommand(action, payload) {
    this.socket.emit('gm:command', {
      event: 'gm:command',
      data: { action, payload },
      timestamp: new Date().toISOString()
    });
  }

  /** @private Session-scoped localStorage key for the dedup guard. */
  _scannedKey() {
    return this.currentSessionId ? `networkedScannedTokens:${this.currentSessionId}` : null;
  }

  /**
   * Persist the dedup guard (scannedTokens) under a session-scoped key so it
   * survives a page reload before sync:full re-populates it (TQ-7).
   */
  persistScannedTokens() {
    const key = this._scannedKey();
    if (!key) return;
    try {
      localStorage.setItem(key, JSON.stringify([...this.scannedTokens]));
    } catch (e) {
      this.debug?.log?.(`[NetworkedStorage] persist scannedTokens failed: ${e.message}`, true);
    }
  }

  /**
   * Rehydrate the dedup guard from persisted state (covers the pre-sync:full
   * window after a reload). Mutates the Set IN PLACE to preserve the shared
   * reference UnifiedDataManager adopts via _syncScannedTokens.
   * @private
   */
  _rehydrateScannedTokens() {
    try {
      const sid = localStorage.getItem('networkedSessionId');
      if (!sid) return;
      this.currentSessionId = sid;
      const saved = localStorage.getItem(this._scannedKey());
      if (saved) {
        const arr = JSON.parse(saved);
        if (Array.isArray(arr)) arr.forEach(t => this.scannedTokens.add(t));
      }
    } catch (e) {
      this.debug?.log?.(`[NetworkedStorage] rehydrate scannedTokens failed: ${e.message}`, true);
    }
  }

  /**
   * Initialize storage
   * Event listeners are handled by NetworkedSession which owns the socket.
   * Rehydrates the dedup guard so duplicate detection survives reloads even
   * before sync:full arrives (TQ-7).
   * @returns {Promise<void>}
   */
  async initialize() {
    this._rehydrateScannedTokens();
  }

  /**
   * Add transaction - delegates to backend
   * @param {Transaction} transaction - Transaction data
   * @returns {Promise<TransactionResult>}
   */
  async addTransaction(transaction) {
    // Validate required fields
    if (!transaction || !transaction.teamId) {
      return {
        success: false,
        error: 'Transaction must have teamId'
      };
    }

    // Check socket connection
    if (!this.isReady()) {
      this.debug?.log('[NetworkedStorage] Cannot add transaction: socket not connected', true);
      return {
        success: false,
        error: 'Socket not connected'
      };
    }

    this.debug?.log(`[NetworkedStorage] Submitting transaction: ${transaction.tokenId} for team ${transaction.teamId}`);

    // Backend STRICTLY requires the AsyncAPI envelope {event, data, timestamp}
    // (adminEvents.js rejects an unwrapped payload with VALIDATION_ERROR). Mirror
    // the same envelope _emitCommand uses. CC-5.
    this.socket.emit('transaction:submit', {
      event: 'transaction:submit',
      data: {
        tokenId: transaction.tokenId,
        teamId: transaction.teamId,
        deviceId: transaction.deviceId,
        deviceType: 'gm',
        mode: transaction.mode,
        summary: transaction.summary ?? null,
        timestamp: transaction.timestamp || new Date().toISOString()
      },
      timestamp: new Date().toISOString()
    });

    // Mark locally for duplicate prevention
    if (transaction.tokenId) {
      this.scannedTokens.add(transaction.tokenId);
    }

    // Return pending - actual result comes via WebSocket broadcast
    return {
      success: true,
      pending: true
    };
  }

  /**
   * Remove transaction - delegates to backend
   * @param {string} transactionId - Transaction ID
   * @returns {Promise<TransactionResult>}
   */
  async removeTransaction(transactionId) {
    if (!this.isReady()) {
      this.debug?.log('[NetworkedStorage] Cannot remove transaction: socket not connected', true);
      return { success: false, error: 'Socket not connected' };
    }

    this.debug?.log(`[NetworkedStorage] Removing transaction: ${transactionId}`);

    this._emitCommand('transaction:delete', { transactionId });

    return { success: true, pending: true };
  }

  /**
   * Get all transactions from local cache
   * @returns {Array}
   */
  getTransactions() {
    return this.transactions;
  }

  /**
   * Get team scores from backend cache
   * @returns {Array}
   */
  getTeamScores() {
    if (this.backendScores.size === 0) {
      return [];
    }

    return Array.from(this.backendScores.entries())
      .map(([teamId, score]) => ({
        teamId,
        score: score.currentScore,
        baseScore: score.baseScore,
        bonusScore: score.bonusPoints,
        tokenCount: score.tokensScanned,
        completedGroups: score.completedGroups?.length || 0,
        adminAdjustments: score.adminAdjustments || [],
        isFromBackend: true
      }))
      .sort((a, b) => b.score - a.score);
  }

  /**
   * Adjust team score - delegates to backend
   * @param {string} teamId - Team identifier
   * @param {number} delta - Score adjustment
   * @param {string} reason - Reason for adjustment
   * @returns {Promise<TransactionResult>}
   */
  async adjustTeamScore(teamId, delta, reason) {
    if (!this.isReady()) {
      this.debug?.log('[NetworkedStorage] Cannot adjust score: socket not connected', true);
      return { success: false, error: 'Socket not connected' };
    }

    this.debug?.log(`[NetworkedStorage] Adjusting score for team ${teamId}: ${delta > 0 ? '+' : ''}${delta} (${reason})`);

    this._emitCommand('score:adjust', { teamId, delta, reason });

    return { success: true, pending: true };
  }

  /**
   * Get unified game activity
   * Matches LocalStorage.getGameActivity() API for parity
   * @returns {Object} { tokens: Array, stats: Object }
   */
  getGameActivity() {
    return buildGameActivity({
      transactions: this.transactions,
      playerScans: this.playerScans,
      tokenManager: this.tokenManager,
      options: {
        transactionFilter: (tx) => !tx.status || tx.status === 'accepted',
        pointsFallback: (tx) => calculateTokenValue({
          valueRating: tx.valueRating,
          memoryType: tx.memoryType
        })
      }
    });
  }

  /**
   * Create a new session - delegates to backend
   * @param {string} name - Session name
   * @param {Array} teams - Initial teams
   * @returns {Promise<Object>}
   */
  async createSession(name, teams) {
    if (!this.isReady()) {
      this.debug?.log('[NetworkedStorage] Cannot create session: socket not connected', true);
      return { success: false, error: 'Socket not connected' };
    }

    this.debug?.log(`[NetworkedStorage] Creating session: ${name}`);

    this._emitCommand('session:create', { name, teams });

    return { pending: true };
  }

  /**
   * End the current session - delegates to backend
   * @returns {Promise<void>}
   */
  async endSession() {
    if (!this.isReady()) {
      this.debug?.log('[NetworkedStorage] Cannot end session: socket not connected', true);
      return;
    }

    this.debug?.log('[NetworkedStorage] Ending session');

    this._emitCommand('session:end', {});
  }

  /**
   * Get current session info
   * @returns {SessionInfo|null}
   */
  getCurrentSession() {
    return this.currentSessionId ? {
      sessionId: this.currentSessionId,
      status: 'active'
    } : null;
  }

  /**
   * Pause the current session - delegates to backend
   * @returns {Promise<Object>}
   */
  async pauseSession() {
    if (!this.isReady()) {
      this.debug?.log('[NetworkedStorage] Cannot pause session: socket not connected', true);
      return { success: false, error: 'Socket not connected' };
    }

    this.debug?.log('[NetworkedStorage] Pausing session');

    this._emitCommand('session:pause', {});

    return { success: true, pending: true };
  }

  /**
   * Resume the current session - delegates to backend
   * @returns {Promise<Object>}
   */
  async resumeSession() {
    if (!this.isReady()) {
      this.debug?.log('[NetworkedStorage] Cannot resume session: socket not connected', true);
      return { success: false, error: 'Socket not connected' };
    }

    this.debug?.log('[NetworkedStorage] Resuming session');

    this._emitCommand('session:resume', {});

    return { success: true, pending: true };
  }

  /**
   * Reset all scores - delegates to backend
   * @returns {Promise<Object>}
   */
  async resetScores() {
    if (!this.isReady()) {
      this.debug?.log('[NetworkedStorage] Cannot reset scores: socket not connected', true);
      return { success: false, error: 'Socket not connected' };
    }

    this.debug?.log('[NetworkedStorage] Resetting all scores');

    this._emitCommand('score:reset', {});

    return { success: true, pending: true };
  }

  // ========================================
  // Cache update methods for NetworkedSession
  // ========================================

  /**
   * Set transactions from sync:full
   * @param {Array} transactions
   */
  setTransactions(transactions) {
    this.transactions = transactions;
  }

  /**
   * Add transaction from broadcast (prevents duplicates)
   * @param {Object} tx
   */
  addTransactionFromBroadcast(tx) {
    const exists = this.transactions.some(t => t.id === tx.id);
    if (!exists) {
      this.transactions.push(tx);
    }

    // A7/F-GMS-05: a transaction:new broadcast means the token is claimed
    // session-wide (GM dedup is global). Mark it locally so a re-scan on THIS
    // device is blocked up-front instead of showing an optimistic success the
    // backend will reject as duplicate. Mutates the Set in place (shared
    // reference with UnifiedDataManager via _syncScannedTokens).
    if (tx.tokenId) {
      this.scannedTokens.add(tx.tokenId);
      this.persistScannedTokens();
    }
  }

  /**
   * Remove transaction from local cache on a transaction:deleted broadcast.
   * Mirror of addTransactionFromBroadcast: cache-only — must NOT re-issue
   * the transaction:delete gm:command (F-GMS-03: every connected GM would
   * echo the delete back to the backend, and the cache would stay stale
   * until the next sync:full).
   * Emits transaction:deleted so UI consumers (badge, history, Game
   * Activity, scoreboards) refresh.
   * @param {string} transactionId
   */
  removeTransactionFromBroadcast(transactionId) {
    const index = this.transactions.findIndex(t => t.id === transactionId);
    if (index === -1) return;

    const [removed] = this.transactions.splice(index, 1);

    this.dispatchEvent(new CustomEvent('transaction:deleted', {
      detail: { transactionId, transaction: removed }
    }));
  }

  /**
   * Set backend scores for a team
   * @param {string} teamId
   * @param {Object} scoreData
   */
  setBackendScores(teamId, scoreData) {
    this.backendScores.set(teamId, scoreData);
  }

  /**
   * Reset all backend scores to zero (preserves team entries)
   * @returns {Array<string>} Team IDs that were reset
   */
  resetBackendScores() {
    const teamIds = Array.from(this.backendScores.keys());
    for (const teamId of teamIds) {
      const scoreData = this.backendScores.get(teamId);
      this.backendScores.set(teamId, {
        ...scoreData,
        currentScore: 0,
        baseScore: 0,
        bonusPoints: 0,
        tokensScanned: 0,
        completedGroups: [],
        adminAdjustments: []
      });
    }
    return teamIds;
  }

  /**
   * Clear all backend scores (removes all entries)
   */
  clearBackendScores() {
    this.backendScores.clear();
  }

  /**
   * Set scanned tokens from sync
   * @param {Array} tokens
   */
  setScannedTokens(tokens) {
    // UNION in place (NOT `new Set`): a gap-scanned-but-unconfirmed token must
    // survive the server sync, and replacing the Set would desync the reference
    // UnifiedDataManager shares via _syncScannedTokens. Explicit removals flow
    // through unmarkTokenAsScanned; new sessions clear via resetForNewSession. TQ-7.
    (tokens || []).forEach(t => this.scannedTokens.add(t));
    this.persistScannedTokens();
  }

  /**
   * Set player scans from sync:full
   * @param {Array} scans
   */
  setPlayerScans(scans) {
    this.playerScans = scans;
  }

  /**
   * Add player scan from broadcast (prevents duplicates)
   * @param {Object} scan
   */
  addPlayerScan(scan) {
    const exists = this.playerScans.some(s => s.id === scan.id);
    if (!exists) {
      this.playerScans.push(scan);
    }
  }

  /**
   * Set current session ID
   * @param {string} sessionId
   */
  setSessionId(sessionId) {
    this.currentSessionId = sessionId;
    // Persist so a future reload can rehydrate the right session-scoped guard (TQ-7).
    try { localStorage.setItem('networkedSessionId', sessionId); } catch { /* ignore */ }
  }

  /**
   * Dispose of resources
   */
  dispose() {
    // NetworkedStorage doesn't own the socket, just references it
    // Cleanup is handled by NetworkedSession
  }
}
